/*
Tries to drop the given number of units.
Does not drop if would go below 9 units.
Returns true if the drop succeeds.
*/
public boolean dropClass(int drop) {
if (units-drop >= 9) {
setUnits(units - drop); // NOTE send self a message
return(true);
}
return(false);
}
